from typing import List

class Solution:
    def constructDistancedSequence(self, n: int) -> List[int]:
        def backtrack(pos):
            if pos == length:
                return True
            if sequence[pos] != 0:
                return backtrack(pos + 1)
            for num in range(n, 0, -1):
                if used[num]:
                    continue
                if num == 1:
                    sequence[pos] = num
                    used[num] = True
                    if backtrack(pos + 1):
                        return True
                    used[num] = False
                    sequence[pos] = 0
                elif pos + num < length and sequence[pos + num] == 0:
                    sequence[pos] = sequence[pos + num] = num
                    used[num] = True
                    if backtrack(pos + 1):
                        return True
                    used[num] = False
                    sequence[pos] = sequence[pos + num] = 0
            return False

        length = 2 * n - 1
        sequence = [0] * length
        used = [False] * (n + 1)
        backtrack(0)
        return sequence
```

This solution uses a backtracking approach to construct the sequence. It tries to place the largest possible number first to ensure the sequence is lexicographically largest. The `backtrack` function attempts to fill the sequence starting from position `pos`, and it tries numbers from `n` down to `1`. If a number can be placed at the current position and the required distance ahead, it places the number and continues. If placing a number doesn't lead to a solution, it backtracks by removing the number and trying the next smaller number. The process continues until a valid sequence is found.
